@ARTICLE{34267029 [Indexed for MEDLINE],
	author = {Sekiguchi Y and Iizuka H and Takizawa H and Mitsumori T and Tomita S and Izumi H and Okubo M and Miyake K and Osawa T and Sawada T and Yoshikawa S and Noguchi M},
	title = {Use of Ibrutinib in 10 Patients with Treatment-Naïve or Relapsed/Refractory Chronic Lymphocytic Leukemia/Small Lymphocytic Lymphoma in Real-World Clinical Practice -A Report from a Single Medical Institution.},
	journal = {Gan To Kagaku Ryoho},
	year = {2021},
	abstract = {In Japan, ibrutinib has been approved as both a front-line and later-line treatment for chronic leukemia/small lymphocytic lymphoma(CLL/SLL). However, little is known about the actual outcomes and adverse events(AEs)associated with the use of ibrutinib in Japanese patients. OBJECTIVE: The outcomes and AEs of patients treated with ibrutinib in a real-world setting were investigated. METHODS: A retrospective cohort study of all patients with CLL/SLL who were treated with ibrutinib at a single institution was conducted. RESULT: In total, 10 patients, including 5 treatment-naïve patients(50%), were enrolled. The median follow-up period was 9.8 months(range, 0.2-21.6 months), and the estimated overall response rate (ORR: complete remission plus partial remission)was 60%. The median overall survival and progression-free survival outcomes were not reached. During the follow-up period, 4 patients(40%)had at least one AE and 1 patient(10%)had at least one grade≥3 AE. Ibrutinib was discontinued in 4 patients(40%)because of AEs in 2 patients(20%), the progression of CLL in 1 patient(10%), and financial reasons in 1 patient(10%). Richter's transformation did not occur in any of the cases. CONCLUSION: The ORR was lower(60%)than that observed in clinical trials. The frequency and severity of AEs were both relatively low, although the discontinuation rate was high(40%). Patient education and medication adherence were considered important.},
	pmid = {34267029 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.pec.2021.06.025,
	author = {Ector GI and Verweij L and Hermens RP and Blijlevens NM},
	title = {Filling the gaps of patient information needs and information perception in chronic myeloid leukemia with the patient-physician co-produced web-based platform CMyLife.},
	journal = {Patient Educ Couns},
	year = {2022},
	abstract = {BACKGROUND: For patients with chronic myeloid leukemia, a web-based platform CMyLife was developed. Its aim is to enhance patient empowerment, by adequate information provision, among others. Before evaluating its effect, information provision and needs in current care were assessed. OBJECTIVE: To assess patients' evaluation of received information and information needs before CMyLife utilization and whether this information source is used correspondingly. Additionally, we explored predicting patient factors in information perception. PATIENT INVOLVEMENT: CMyLife platform was developed with active patient participation. METHODS: We conducted a cross-sectional survey among 203 CML patients before launch of the CMyLife platform, using validated questionnaires on information provision and predictive factors. We focused on website utilization during the first 3 years, using Google Analytics. Regression analyses were performed to determine influence of patient factors on information perception. RESULTS: Global perceived information provision was scored 42.8 (0-100). Information on other services such as rehabilitation and psychological support, and effects of treatment on sexuality showed room for improvement. One out of 3 knew where to find useful health information online. But more information was desired by 36% of them. Age ≥65 years, time since diagnosis and low education were positively associated with this need. Pages on medication and side effects were visited the most. DISCUSSION: To fill the gap in perceived provision and needs, information should be adjusted more to the individual in content, manner and timing. Age, time since diagnosis, and educational level are of influence in perceived information, and specific needs within these groups should be further explored. PRACTICAL VALUE: CMyLife provides reliable and up-to-date information for low eHealth literacy skilled patients concerning multiple topics indicated by patients.},
	doi = {10.1016/j.pec.2021.06.025},
	pmid = {34226069 [Indexed for MEDLINE]}
}

@ARTICLE{10.1093/abm/kaab035,
	author = {Hyland KA and Nelson AM and Eisel SL and Hoogland AI and Ibarz-Pinilla J and Sweet K and Jacobsen PB and Knoop H and Jim HSL},
	title = {Fatigue Perpetuating Factors as Mediators of Change in a Cognitive Behavioral Intervention for Targeted Therapy-Related Fatigue in Chronic Myeloid Leukemia: A Pilot Study.},
	journal = {Ann Behav Med},
	year = {2022},
	abstract = {BACKGROUND: Cognitive behavioral therapy for targeted-therapy related fatigue (CBT-TTF) has demonstrated preliminary efficacy in reducing fatigue in patients treated with tyrosine kinase inhibitors (TKIs) for chronic myeloid leukemia (CML). PURPOSE: The aim of the current analyses was to explore whether fatigue perpetuating factors (disturbed sleep/wake cycle, dysregulated activity patterns, maladaptive cognitions about fatigue and cancer, insufficient processing of cancer and treatment, inadequate social support and interactions, heightened fear of cancer progression) changed over time in patients receiving CBT-TTF, and whether the effect of CBT-TTF on fatigue was mediated by these factors. METHODS: Secondary data analyses were conducted from a pilot randomized controlled trial. Patients with CML treated with a TKI who reported moderate to severe fatigue were randomized 2:1 to CBT-TTF delivered via FaceTime for iPad or a waitlist control condition (WLC). Self-report measures of fatigue and fatigue perpetuating factors were obtained before randomization and post-intervention (i.e., approximately 18 weeks later). Mixed model and mediation analyses using bootstrap methods were used. RESULTS: A total of 36 participants (CBT-TTF n = 22, WLC n = 14) who had baseline and 18-week follow-up data and attended >5 sessions for CBT-TTF were included. Participants randomized to CBT-TTF reported improvements in activity (mental, physical, social, p's ≤ .023) and cognitions (helplessness, catastrophizing, focusing on symptoms, self-efficacy, p's ≤ .003) compared to WLC. Mental activity, social activity, self-efficacy, helplessness, and focusing on symptoms, as well as sleep and insufficient processing (avoidance) mediated the relationship between treatment group and fatigue. CONCLUSIONS: CBT-TTF appears to improve TKI-related fatigue in CML patients through changes in behavior (sleep, activity patterns) and cognitions about fatigue and cancer. A larger randomized controlled trial is warranted to confirm these findings.},
	doi = {10.1093/abm/kaab035},
	pmid = {33991085 [Indexed for MEDLINE]},
	note = {PMC8832107}
}

@ARTICLE{10.1016/j.ejon.2021.101951,
	author = {Vinette B and Bilodeau K},
	title = {Progression of self-management learning experiences of young adults following an allogeneic hematopoietic stem cell transplantation: A qualitative study.},
	journal = {Eur J Oncol Nurs},
	year = {2021},
	abstract = {PURPOSE: Hematological diseases are among the most common forms of cancer that can affect young adults. Hematopoietic stem cell transplantation is a common intervention to treat blood-related cancers such as leukemia and lymphoma. Allogeneic stem cell transplants can provoke many acute and chronic symptoms. Young adult cancer survivors are expected to develop expertise to self-manage these symptoms. However, learning self-management can be quite challenging for young adults. This paper aims to describe the symptoms self-management learning experiences of young adults following an allogeneic stem cell transplant. METHOD: A qualitative descriptive study was conducted to describe self-management learning experiences of young adults (18-39 years old) following an allogeneic stem cell transplant. Semi-structured interviews were conducted (n = 7, mean age 26 years old, mean time since allogeneic stem cell transplant was 14,71 months). Iterative qualitative content analysis was performed. RESULTS: Participants who had undergone an allogeneic stem cell transplant described learning self-management as a progressive process, with expertise having to be developed through experience. Certain factors could positively or negatively affect the learning process and hence the development of this self-management expertise. With time, these young adults developed interoceptive ability and body awareness related to their symptoms, which influenced their self-management. CONCLUSIONS: Following an allogeneic stem cell transplant, young adults need to be supported during their survivorship to develop self-management expertise. Nurses must adapt care according to patients' level of expertise to promote autonomy, development of interoceptive ability, and acquisition of self-management skills.},
	doi = {10.1016/j.ejon.2021.101951},
	pmid = {33774375 [Indexed for MEDLINE]}
}

@ARTICLE{10.1080/10428194.2021.1901096,
	author = {Pemmaraju N and Wilson NR and Clementi Doan T and Qiao W and Peterson SK and Zoeller V and Schorr A and Verstovsek S},
	title = {Myeloproliferative neoplasm questionnaire: assessing patient disease knowledge in the modern digital information era.},
	journal = {Leuk Lymphoma},
	year = {2021},
	abstract = {There is growing Internet and social media use among patients with rare blood cancers, notably myeloproliferative neoplasms (MPNs). A 38-item online questionnaire was developed to assess patients' (n = 983) disease understanding and use of online resources regarding MPN. Many responders (74%) reported unawareness of additional mutations beyond their primary molecular marker(s); 32% were unsure of their prognostic risk stratification. Additionally, 89% reported using online resources (Facebook (61%); Google/Google+ (42%); YouTube (34%); blogs (26%); Twitter (5%)) to seek information about MPN. Despite this, results showed many gaps in patients' basic disease knowledge. Our findings suggest an important difference in social media habits between physicians and patients: physicians are rapidly adopting Twitter as their preferred medium for sharing medical knowledge; however, patients often prefer other social mediums. Educational campaigns should be designed in more personalized ways, aiming to fit a variety of online platforms to maximize reach and impact for patients with MPN.},
	doi = {10.1080/10428194.2021.1901096},
	pmid = {33749512 [Indexed for MEDLINE]},
	note = {PMC9938727}
}

@ARTICLE{10.6004/jadpro.2021.12.1.5,
	author = {Goodrich A},
	title = {Advanced Practice Perspectives on Preventing and Managing Tumor Lysis Syndrome and Neutropenia in Chronic Lymphocytic Leukemia.},
	journal = {J Adv Pract Oncol},
	year = {2021},
	abstract = {Tumor lysis syndrome (TLS) and neutropenia are significant toxicities in the treatment of chronic lymphocytic leukemia (CLL). Both TLS and neutropenia can lead to potentially life-threatening complications for patients with chronic lymphocytic leukemia undergoing antineoplastic therapy. This article focuses on diligent risk assessment, prophylaxis, early identification, monitoring, patient education, and prompt intervention for TLS and neutropenia. These are all necessary steps to reduce life-threatening complications. Guidelines are available for risk assessments for both TLS and neutropenia. Once risk is established, prophylaxis and monitoring recommendations can be found in available guidelines. There are no established guidelines or widely used decision-making standards for the treatment of clinical TLS. General management strategies are well documented in the literature, with some degree of customization to each individual patient. If fever occurs in the setting of neutropenia, there are well-established guidelines for management, including guidance on anti-infective agents and use of growth factors. In addition, awareness and proper actions regarding TLS and neutropenia are key to preventing treatment delays, dose reductions, or treatment discontinuation. Adequate planning for TLS and neutropenia is critical to optimize patient outcomes.},
	doi = {10.6004/jadpro.2021.12.1.5},
	pmid = {33552662},
	note = {PMC7844191}
}

@ARTICLE{10.1097/CIN.0000000000000690,
	author = {Song CE and An M},
	title = {The Self-management Smartphone Application for Cancer Survivors, ReLive: Development and Usability Testing.},
	journal = {Comput Inform Nurs},
	year = {2021},
	abstract = {ReLive is a nursing theory-driven and evidence-based smartphone application that aims to promote self-management among cancer survivors. It has been designed to display symptom measurement results in different traffic light colors, depending on the severity of a user's symptoms (eg, severe symptoms are presented in red). Therefore, it is easy for users to draw inferences about changes in their symptoms. Further, users can simultaneously set several physical activity goals and monitor their performance. Social support, self-efficacy, and quality of life of a user can also be monitored regularly. This study investigated the usability of this application. An iterative formative test, including a cognitive walkthrough and face-to-face interviews, was conducted. Participants were seven individuals with a diagnosis of chronic myeloid leukemia. The ease of use and understanding, acceptability, and usefulness of the application were evaluated. The results revealed that the participants had evaluated ReLive positively. This program could be used as an intervention to deliver health information and manage their performance. Further research is needed to assess the application's effects on self-management among survivors of various types of cancers.},
	doi = {10.1097/CIN.0000000000000690},
	pmid = {33214389 [Indexed for MEDLINE]}
}

@ARTICLE{10.1007/s00520-020-05819-w,
	author = {Nørskov KH and Overgaard D and Boesen J and Struer A and El-Azem SEWD and Tolver A and Lomborg K and Kjeldsen L and Jarden M},
	title = {Patient ambassador support in newly diagnosed patients with acute leukemia during treatment: a feasibility study.},
	journal = {Support Care Cancer},
	year = {2021},
	abstract = {PURPOSE: This study investigated the feasibility of patient ambassador support in newly diagnosed patients with acute leukemia during treatment. METHODS: A multicenter single-arm feasibility study that included patients newly diagnosed with acute leukemia (n = 36) and patient ambassadors previously treated for acute leukemia (n = 25). Prior to the intervention, all patient ambassadors attended a 6-h group training program. In the intervention, patient ambassadors provided 12 weeks of support for patients within 2 weeks of being diagnosed. Outcome measures included feasibility (primary outcome), safety, anxiety, and depression measured by the Hospital Anxiety and Depression Scale, quality of life by the Functional Assessment of Cancer Therapy-Leukemia and the European Organization for Research and Treatment of Cancer Quality of Life Questionnaire, and symptom burden by MD Anderson Symptom Inventory, the Patient Activation Measure, and the General Self-Efficacy Scale. RESULTS: Patient ambassador support was feasible and safe in this population. Patients and patient ambassadors reported high satisfaction with the individually adjusted support, and patients improved in psychosocial outcomes over time. Patient ambassadors maintained their psychosocial baseline level, with no adverse events, and used the available support to exchange experiences with other patient ambassadors and to manage challenges. CONCLUSION: The patient ambassador support program is feasible and has the potential to be a new model of care incorporated in the hematology clinical care setting, creating an active partnership between patients and former patients. This may strengthen the existing supportive care services for patients with acute leukemia. TRIAL REGISTRATION: NCT03493906.},
	doi = {10.1007/s00520-020-05819-w},
	pmid = {33051828 [Indexed for MEDLINE]},
	note = {PMC8062400}
}

@ARTICLE{10.1177/1078155220964539,
	author = {Tan BK and Chua SS and Chen LC and Chang KM and Balashanker S and Bee PC},
	title = {Acceptability of pharmacist-led interventions to resolve drug-related problems in patients with chronic myeloid leukaemia.},
	journal = {J Oncol Pharm Pract},
	year = {2021},
	abstract = {PURPOSE: Chronic myeloid leukaemia (CML) patients on long-term tyrosine kinase inhibitor (TKI) therapy are susceptible to drug-related problems (DRPs). This study aimed to evaluate the acceptability and outcomes of pharmacist-led interventions on DRPs encountered by CML patients. METHODS: This study included participants from the intervention arm of a randomised controlled trial which was conducted to evaluate the effects of pharmacist-led interventions on CML patients treated with TKIs. Participants were recruited and followed up in the haematology clinics of two hospitals in Malaysia from March 2017 to January 2019. A pharmacist identified DRPs and helped to resolve them. Patients were followed-up for six months, and their DRPs were assessed based on the Pharmaceutical Care Network Europe Classification for DRP v7.0. The identified DRPs, the pharmacist's interventions, and the acceptance and outcomes of the interventions were recorded. A Poisson multivariable regression model was used to analyse factors associated with the number of identified DRPs per participant. RESULTS: A total of 198 DRPs were identified from 65 CML patients. The median number of DRPs per participants was 3 (interquartile range: 2, 4). Most participants (97%) had at least one DRP, which included adverse drug events (45.5%), treatment ineffectiveness (31.5%) and patients' treatment concerns or dissatisfaction (23%). The 228 causes of DRPs identified comprised the following: lack of disease or treatment information, or outcome monitoring (47.8%), inappropriate drug use processes (23.2%), inappropriate patient behaviour (19.9%), suboptimal drug selection (6.1%), suboptimal dose selection (2.6%) and logistic issues in dispensing (0.4%). The number of concomitant medications was significantly associated with the number of DRPs (adjusted Odds Ratio: 1.100; 95% CI: 1.005, 1.205; p = 0.040). Overall, 233 interventions were made. These included providing patient education on disease states or TKI-related side effects (75.1%) and recommending appropriate instructions for taking medications (7.7%). Of the 233 interventions, 94.4% were accepted and 83.7% were implemented by the prescriber or patient. A total of 154 DRPs (77.3%) were resolved. CONCLUSIONS: The pharmacist-led interventions among CML patients managed to identify various DRPs, were well accepted by both TKI prescribers and patients, and had a high success rate of resolving the DRPs.},
	doi = {10.1177/1078155220964539},
	pmid = {33040675 [Indexed for MEDLINE]}
}

@ARTICLE{10.1007/s00277-020-04045-y,
	author = {Zerbit J and Chevret S and Bernard S and Kroemer M and Ablard C and Harel S and Brice P and Madelaine I and Thieblemont C},
	title = {Improved time to treatment failure and survival in ibrutinib-treated malignancies with a pharmaceutical care program: an observational cohort study.},
	journal = {Ann Hematol},
	year = {2020},
	abstract = {Ibrutinib treatment has been shown to increase survival in patients with B cell malignancies. Real-life data suggest a large part of discontinuations are due to toxicities, impairing ibrutinib efficacy. We aimed to assess the impact of a pharmaceutical care program on the efficacy and safety of ibrutinib. This single-center, cohort, observational study enrolled patients with B cell malignancies. Patients were either assigned to the program or to receive usual care, based on physician decision. The program was conducted by clinical pharmacists specializing in oncology and included patient education for management of toxicities, adherence monitoring, interventions to reduce drug-drug interactions, and follow-up of transition from hospital to community. Between February 2014 and May 2017, we enrolled 155 patients, including 42 (27%) who were allocated to the program group and 113 (73%) to the usual care group. The effect of the program was beneficial in terms of time to treatment failure (p = 0.0005). The 30-month progression-free and overall survivals were significantly superior in the program group (respectively p = 0.002 and p = 0.004). Grade 3 or higher adverse events occurred more frequently for patients in the usual care group (15%) than program group (8%). A pharmaceutical care program provides a personalized environment for outpatient monitoring and control of the key risks associated with oral anticancer agents. This study shows evidence that management of ibrutinib treatment by clinical pharmacists results in significant improvement in survival and better tolerance than usual care.},
	doi = {10.1007/s00277-020-04045-y},
	pmid = {32483668 [Indexed for MEDLINE]},
	note = {PMC7316844}
}
